-- ----------------------------------------------------------------------------
-- vw_users: Login identities for the demo (stub auth).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_users WITH (security_invoker = ON) AS
SELECT
  t.user_id,
  t.name,
  t.email,
  t.role,                                                                       -- coordinator | bride | groom
  t.display_name
FROM users t;

-- ----------------------------------------------------------------------------
-- vw_tables: Physical reception tables. Guests are assigned to one Table each.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_tables WITH (security_invoker = ON) AS
SELECT
  t.table_id,
  t.name,
  t.label,                                                                      -- Friendly label e.g. 'Head Table', 'Cousins'.
  t.seats,                                                                      -- Physical capacity.
  calc_tables_head_count(t.table_id) AS head_count,
  calc_tables_open_seats(t.table_id) AS open_seats,
  calc_tables_over_capacity(t.table_id) AS over_capacity,
  calc_tables_raw_happiness(t.table_id) AS raw_happiness,                       -- Sum of EffectiveScore for relationships whose seated table matches this one.
  calc_tables_violation_count(t.table_id) AS violation_count,                   -- Number of must-not pairs seated at this table.
  calc_tables_happiness(t.table_id) AS happiness,                               -- Net happiness: raw affinity minus capacity penalty minus side-skew penalty.
  calc_tables_grade(t.table_id) AS grade,
  calc_tables_bride_side_count(t.table_id) AS bride_side_count,                 -- Number of bride-side guests at this table.
  calc_tables_groom_side_count(t.table_id) AS groom_side_count,                 -- Number of groom-side guests at this table.
  calc_tables_side_skew(t.table_id) AS side_skew                                -- Absolute difference between bride and groom side counts.
FROM tables t;

-- ----------------------------------------------------------------------------
-- vw_guests: Wedding guests. Each is assigned to one Table.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_guests WITH (security_invoker = ON) AS
SELECT
  t.guest_id,
  t.name,
  t.full_name,
  t.side,                                                                       -- bride | groom | both
  t.dietary,                                                                    -- none | veg | vegan | gf | kosher
  t.language,                                                                   -- en | es | fr
  t.age_band,                                                                   -- child | adult | senior
  t.assigned_table,                                                             -- FK to Tables.TableId. Editable — moves the guest.
  calc_guests_table_label(t.guest_id) AS table_label,
  calc_guests_table_seats(t.guest_id) AS table_seats,
  calc_guests_table_head_count(t.guest_id) AS table_head_count,
  calc_guests_relationships_as_a(t.guest_id) AS relationships_as_a,
  calc_guests_relationships_as_b(t.guest_id) AS relationships_as_b,
  calc_guests_satisfaction_a(t.guest_id) AS satisfaction_a,                     -- Sum of EffectiveScore on relationships where this guest is GuestA and the pair is co-seated.
  calc_guests_satisfaction_b(t.guest_id) AS satisfaction_b,
  calc_guests_satisfaction(t.guest_id) AS satisfaction,                         -- Per-guest happiness rollup.
  calc_guests_mood(t.guest_id) AS mood,
  calc_guests_bride_flag(t.guest_id) AS bride_flag,                             -- 1 if bride-side guest; else 0. Feeds Tables.BrideSideCount.
  calc_guests_groom_flag(t.guest_id) AS groom_flag                              -- 1 if groom-side guest; else 0. Feeds Tables.GroomSideCount.
FROM guests t;

-- ----------------------------------------------------------------------------
-- vw_relationships: Directed-but-symmetric guest-pair affinities. Kind is loves | prefers | avoid | must-not, with a Weight (positive = affinity, negative = friction).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_relationships WITH (security_invoker = ON) AS
SELECT
  t.rel_id,
  t.name,
  t.guest_a,
  t.guest_b,
  t.kind,                                                                       -- loves | prefers | avoid | must-not
  t.weight,                                                                     -- Signed magnitude (positive = wants near, negative = wants apart).
  calc_relationships_guest_a_name(t.rel_id) AS guest_a_name,
  calc_relationships_guest_b_name(t.rel_id) AS guest_b_name,
  calc_relationships_guest_a_table(t.rel_id) AS guest_a_table,
  calc_relationships_guest_b_table(t.rel_id) AS guest_b_table,
  calc_relationships_same_table(t.rel_id) AS same_table,                        -- True iff both ends sit at the same non-empty table.
  calc_relationships_seated_table(t.rel_id) AS seated_table,                    -- If both guests share a table, that table's id; else blank. Drives the per-table aggregations.
  calc_relationships_effective_score(t.rel_id) AS effective_score,              -- Weight when co-seated; else 0. Must-not pairs co-seated produce a large penalty regardless of Weight sign.
  calc_relationships_is_must_not_violation(t.rel_id) AS is_must_not_violation,
  calc_relationships_is_satisfied(t.rel_id) AS is_satisfied,                    -- Positive-affinity pair sitting together, or negative-affinity pair sitting apart.
  calc_relationships_violation_table(t.rel_id) AS violation_table,              -- TableId if this is a must-not violation; else blank.
  calc_relationships_violation_flag(t.rel_id) AS violation_flag                 -- 1 if must-not pair co-seated; else 0. Feeds the per-table ViolationCount aggregation.
FROM relationships t;

